WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT * FROM epub_annotations
WHERE user_id = #{userId}
AND created_at >= #{since}
ORDER BY created_at DESC

SELECT * FROM epub_annotations
WHERE user_id = #{userId}
ORDER BY created_at DESC
